muclient.script:
require "movewindow"
local MIP_ID = "9a8b3c5d1e2f4a6b8c0d2e4f" local WIN = "vikingstatus_" .. GetPluginID() local W, H = 560, 560 local windowinfo local visible = (GetVariable("visible") ~= "0") local tab = GetVariable("tab") or "Stats" local prev_rndz = nil -- last seen RNDZ (round counter) local last_fight = tonumber(GetVariable("last_fight")) or 0 -- rounds the previous combat lasted local TABS = { "Stats", "City", "People", "Settlers", "Goods", "Holds", "Sea", "Map", "Mission", "Feeds" }
local C = { bg = 0x201510, panel = 0x2A1C14, border = 0x604020, label = 0xD0D0D0, dim = 0x808080, text = 0xF0F0F0, head = 0x40C0FF, good = 0x60E060, warn = 0x40C0FF, bad = 0x5050F0, tabbg = 0x301E12, tabsel = 0x604020, title = 0x402818, }
-- terrain char -> colour (BGR), decoded from the live VMR rows local TERRAIN = { ["."] = 0x101010, -- void / walls ["t"] = 0x606060, ["T"] = 0x707070, -- tundra grey ["h"] = 0x20C0C0, ["H"] = 0x20C0C0, -- hills yellow ["A"] = 0x3030D0, -- mountains red ["f"] = 0x208020, ["F"] = 0x30A030, -- forest ["p"] = 0x60C060, -- plains ["W"] = 0xD0A000, ["w"] = 0xD0A000, ["~"] = 0xD0A000, -- water ["r"] = 0x181818, ["="] = 0x303030, -- road / bridge ["P"] = 0x909090, -- gate / passage ["L"] = 0x2080E0, -- lin hold ["S"] = 0x40C0E0, -- settlement ["C"] = 0x2020C0, -- capital ["R"] = 0xC060C0, -- ruins ["M"] = 0x2020C0, -- Midgard (capital) ["*"] = 0xE060E0, -- point of interest ["X"] = 0xFFFFFF, -- you (feed marker) }
local function loc_color(t) t = (t or ""):lower() if t:find("cap") then return 0x2020E0 elseif t:find("lin") then return 0x2080E0 elseif t:find("set") then return 0x40C0E0 elseif t:find("mentor") then return 0x60E060 elseif t:find("blot") then return 0x40E080 elseif t:find("farm") then return 0x40A040 elseif t:find("seer") then return 0xE060C0 elseif t:find("ruin") then return 0xC060C0 else return 0xD0D0D0 end end
local function parse_locs(s) local out = {} if not s or s == "" then return out end for entry in s:gmatch("[^;]+") do local f = {} for tok in entry:gmatch("[^|]*") do if tok ~= "" or #f > 0 then f[#f + 1] = tok end end local i = 1 while i + 3 <= #f do if tonumber(f[i + 2]) and tonumber(f[i + 3]) then out[#out + 1] = { type = f[i], name = f[i + 1], x = tonumber(f[i + 2]), y = tonumber(f[i + 3]) } i = i + 4 else i = i + 1 end end end return out end
local function grad(pct) if pct > 100 then return 0xFFC040 end if pct < 0 then pct = 0 end local r, g if pct >= 50 then r = math.floor(255 * (100 - pct) / 50); g = 220 else r = 255; g = math.floor(220 * pct / 50) end return g * 256 + r end
local function num(s) return tonumber(s) or 0 end
local function split(s, sep) local out = {} if not s or s == "" then return out end local pat = "([^" .. sep .. "]*)" .. sep .. "?" local pos = 1 while pos <= #s + 1 do local st, en, cap = s:find(pat, pos) if not st then break end out[#out + 1] = cap if en < st then break end pos = en + 1 end if out[#out] == "" then out[#out] = nil end return out end
local function clean(s) return (s or ""):gsub("grey:", ""):gsub("gray:", ""):gsub("red:", ""):gsub("green:", ""):gsub("blue:", ""):gsub("yellow:", "") end
local function getvars() local function gv(k) return GetPluginVariable(MIP_ID, k) or "" end local vmip = {} for line in gv("vmip_ser"):gmatch("[^\n]+") do local k, v = line:match("^([^=]+)=(.*)$") if k then vmip[k] = v end end return { hp = num(gv("hp")), hpmax = num(gv("hpmax")), sp = num(gv("sp")), spmax = num(gv("spmax")), enemy_name = gv("enemy_name"), enemy_hp = gv("enemy_hp"), gline1 = gv("gline1"), gline2 = gv("gline2"), uptime = gv("uptime"), lag = gv("lag"), }, vmip end
-- number to commit on patrol: a user override if set, else the last patrol's count local function patrol_number(vmip) local override = tonumber(GetVariable("patrol_num")) if override then return override end return tonumber((split(vmip.PATROL or "", "|"))[1]) end
local GOODS_NAME = { t = "timber", i = "iron", g = "grain", f = "furs", h = "fish", m = "mead", a = "amber", r = "runeston", s = "spoils" }
-- "0|Name|a|b;1|Name2|..." -> map idx -> field list local function parse_idx_table(s) local out = {} for entry in (s or ""):gmatch("[^;]+") do local f = split(entry, "|") local i = tonumber(f[1]) if i then out[i] = f end end return out end
-- known settlements (from the in-game Settlements list); vikloc overrides local DEFAULT_LOCNAMES = { ["32|16"] = "Midgard", ["14|8"] = "Lodbrok's Hold", ["52|6"] = "Eiriksby", ["10|16"] = "Imaird", ["54|16"] = "Holmgard", ["34|6"] = "Hafrfjord", ["30|26"] = "Uppsala", ["16|24"] = "Borgarfjord", ["50|24"] = "Vestergotland", ["20|20"] = "Sverkersby", ["46|8"] = "Ericsgard", ["12|22"] = "Birka", ["52|20"] = "Lejre", ["22|8"] = "Nidaros", ["50|27"] = "Jarl", ["19|25"] = "Seer", ["51|16"] = "Berserker", ["4|28"] = "Blot", }
-- trade-hold index -> city name (what you trade against in-game). VREP gives -- the lineage/clan name instead, which is confusing, so map it to the city. local HOLDCITY = { [0] = "Midgard", [1] = "Lodbrok's Hold", [2] = "Eiriksby", [3] = "Imaird", [4] = "Holmgard", [5] = "Hafrfjord", [6] = "Uppsala", [7] = "Borgarfjord", [8] = "Vestergotland", [9] = "Sverkersby", [10] = "Ericsgard", [11] = "Birka", [12] = "Lejre", [13] = "Nidaros", }
-- type labels for special places that are not travel towns local DEFAULT_LOCTYPE = { ["50|27"] = "Mentor", ["19|25"] = "Seer", ["51|16"] = "Mentor", ["4|28"] = "Blot", }
-- town <-> Midgard base routes (extracted from the old TinTin aliases); -- any pair is chained as <From>Mid + Mid<To> local ROUTES = { BirMid = { "leave", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "n", "n", "n", "n", "n", "n", "enter" }, BlotMid = { "s", "s", "s", "s", "s", "s", "s", "s", "s", "e", "e", "e", "e", "e", "e", "enter" }, BorMid = { "leave", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "n", "n", "n", "n", "n", "n", "n", "n", "enter" }, EirMid = { "leave", "e", "e", "s", "s", "s", "s", "s", "s", "w", "w", "s", "e", "s", "s", "s", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "enter" }, EriMid = { "leave", "w", "w", "s", "s", "s", "s", "s", "s", "s", "s", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "enter" }, HafMid = { "leave", "s", "s", "s", "s", "s", "s", "s", "s", "s", "s", "w", "w", "enter" }, HolMid = { "leave", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "enter" }, ImaMid = { "leave", "s", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "n", "enter" }, LerMid = { "leave", "n", "n", "n", "n", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "enter" }, LodMid = { "leave", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "s", "s", "s", "s", "s", "s", "s", "s", "enter" }, MidBir = { "leave", "s", "s", "s", "s", "s", "s", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "enter" }, MidBlot = { "leave", "w", "w", "w", "w", "w", "w", "n", "n", "n", "n", "n", "n", "n", "grove" }, MidBor = { "leave", "s", "s", "s", "s", "s", "s", "s", "s", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "enter" }, MidEir = { "leave", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "n", "n", "n", "w", "n", "e", "e", "n", "n", "n", "n", "n", "n", "w", "w", "enter" }, MidEri = { "leave", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "n", "n", "n", "n", "n", "n", "n", "n", "e", "e", "enter" }, MidHaf = { "leave", "e", "e", "n", "n", "n", "n", "n", "n", "n", "n", "n", "n", "enter" }, MidHol = { "leave", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "enter" }, MidIma = { "leave", "s", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "n", "enter" }, MidLer = { "leave", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "s", "s", "s", "s", "enter" }, MidLod = { "leave", "n", "n", "n", "n", "n", "n", "n", "n", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "enter" }, MidNid = { "leave", "n", "n", "n", "n", "n", "n", "n", "n", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "enter" }, MidSeer = { "leave", "w", "w", "w", "s", "s", "s", "s", "enter" }, MidSve = { "leave", "s", "s", "s", "s", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "enter" }, MidUpp = { "leave", "s", "s", "s", "s", "s", "s", "s", "s", "s", "s", "w", "w", "enter" }, MidVas = { "leave", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "s", "s", "s", "s", "e", "e", "s", "s", "s", "s", "w", "w", "enter" }, NidMid = { "leave", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "s", "s", "s", "s", "s", "s", "s", "s", "enter" }, SeerMid = { "leave", "n", "n", "n", "n", "e", "e", "e", "enter" }, SveMid = { "leave", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "e", "n", "n", "n", "n", "enter" }, UppMid = { "leave", "e", "e", "n", "n", "n", "n", "n", "n", "n", "n", "n", "n", "enter" }, VasMid = { "leave", "e", "e", "n", "n", "n", "n", "w", "w", "n", "n", "n", "n", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "w", "enter" }, }
local function vik_send_route(origin, dest) local cmds = {} if origin ~= "Mid" then local leg = ROUTES[origin .. "Mid"] if not leg then return false end for _, c in ipairs(leg) do cmds[#cmds + 1] = c end end if dest ~= "Mid" then local leg = ROUTES["Mid" .. dest] if not leg then return false end for _, c in ipairs(leg) do cmds[#cmds + 1] = c end end for _, c in ipairs(cmds) do Send(c) end return true end
-- travel codes per settlement (routes are built into this plugin now) local TRAVEL_CODE = { ["32|16"] = "Mid", ["14|8"] = "Lod", ["52|6"] = "Eir", ["10|16"] = "Ima", ["54|16"] = "Hol", ["34|6"] = "Haf", ["30|26"] = "Upp", ["16|24"] = "Bor", ["50|24"] = "Vas", ["20|20"] = "Sve", ["46|8"] = "Eri", ["12|22"] = "Bir", ["52|20"] = "Ler", ["22|8"] = "Nid", }
-- user-named map locations (vikloc x y name) local locnames = {} do local s = GetVariable("locnames") if s then for line in s:gmatch("[^\n]+") do local x, y, n = line:match("^(%-?%d+)|(%-?%d+)|(.*)$") if x then locnames[x .. "|" .. y] = n end end end end
local function locname(x, y) local key = x .. "|" .. y return locnames[key] or DEFAULT_LOCNAMES[key] end
function vik_setloc(x, y, name) name = (name or ""):gsub("^%s+", ""):gsub("%s+$", "") local key = x .. "|" .. y if name == "" then locnames[key] = nil else locnames[key] = name end local out = {} for k, n in pairs(locnames) do out[#out + 1] = k .. "|" .. n end SetVariable("locnames", table.concat(out, "\n")) Note("[viking] location (" .. x .. "," .. y .. "): " .. (name == "" and "(cleared)" or name)) vik_draw() end
function vik_travel_click(flags, id) local x, y = id:match("^trav_(%-?%d+)|(%-?%d+)$") if not x then return end local destkey = x .. "|" .. y local dest = TRAVEL_CODE[destkey] if not dest then return end local destname = locname(tonumber(x), tonumber(y)) or dest local rh = false if bit and bit.band then rh = bit.band(flags, 0x20) ~= 0 end if rh then SetVariable("curtown", destkey) SetVariable("curtown_time", tostring(os.time())) Note("[viking] current location set: " .. destname) return end -- two origin candidates: the live map position and the town we last -- travelled to. The map feed lags behind movement, so the NEWER of -- the two wins. local my, vmip = getvars() local hd = split(vmip.VMAPH or "", "|") local px, py = tonumber(hd[3]), tonumber(hd[4]) local live, livekey if px and py then for k, code in pairs(TRAVEL_CODE) do local tx, ty = k:match("^(%-?%d+)|(%-?%d+)$") if math.abs(px - tx) <= 2 and math.abs(py - ty) <= 2 then live, livekey = code, k break end end end local rem, remkey local ck = GetVariable("curtown") if ck and TRAVEL_CODE[ck] then rem, remkey = TRAVEL_CODE[ck], ck end -- click-travel knowledge is authoritative: the map feed only updates on -- the guild tick and lags far behind actual movement. Only discard the -- remembered town if the feed has clearly shown us somewhere ELSE for a -- while (manual trekking since the last click). if rem and px and py then local vm_time = tonumber(GetPluginVariable(MIP_ID, "vmaph_time")) or 0 local ct_time = tonumber(GetVariable("curtown_time")) or 0 if vm_time > ct_time + 180 then local tx, ty = remkey:match("^(%-?%d+)|(%-?%d+)$") if math.abs(px - tx) > 4 or math.abs(py - ty) > 4 then rem, remkey = nil, nil -- wandered off since the last click end end end local origin, originkey if rem then origin, originkey = rem, remkey elseif live then origin, originkey = live, livekey end if not origin then Note("[viking] can't tell where you are - right-click the town you're in, then click your destination") return end if originkey == destkey then Note("[viking] you are already at " .. destname) return end Note("[viking] travelling " .. origin .. " -> " .. dest .. " (" .. destname .. ")") if not vik_send_route(origin, dest) then Note("[viking] no route known for " .. origin .. " -> " .. dest) return end SetVariable("curtown", destkey) SetVariable("curtown_time", tostring(os.time())) end
-- ---------------- drawing helpers ---------------- local ly = 0 -- line cursor local function nl(dy) ly = ly + (dy or 14) end local function txt(x, s, col, font) WindowText(WIN, font or "f", s or "", x, ly, 0, 0, col or C.text) end local function header(s) txt(10, s, C.head, "fb"); nl(15) end
local function bar(x1, x2, label, cur, max, showtext) txt(10, label, C.label) WindowRectOp(WIN, 2, x1, ly + 1, x2, ly + 13, C.panel) local pct = 0 if max > 0 then pct = cur * 100 / max end local fill = math.floor((x2 - x1 - 2) * math.min(pct, 100) / 100) if fill > 0 then WindowRectOp(WIN, 2, x1 + 1, ly + 2, x1 + 1 + fill, ly + 12, grad(pct)) end WindowRectOp(WIN, 1, x1, ly + 1, x2, ly + 13, C.border) txt(x2 + 8, showtext, C.text) nl(17) end
-- ---------------- tab renderers ---------------- local function draw_stats(my, vmip) bar(70, 330, "HP", my.hp, my.hpmax, my.hp .. "/" .. my.hpmax) bar(70, 330, "Seid", num(vmip.SEID), num(vmip.MSEID), (vmip.SEID or "?") .. "/" .. (vmip.MSEID or "?")) bar(70, 330, "Vig", num(vmip.VIG), num(vmip.MVIG), (vmip.VIG or "?") .. "/" .. (vmip.MVIG or "?")) bar(70, 330, "Rad", num(vmip.RAD), num(vmip.MRAD), (vmip.RAD or "?") .. "/" .. (vmip.MRAD or "?")) if my.enemy_name ~= "" then bar(70, 330, "Enemy", num(my.enemy_hp), 100, my.enemy_hp .. "% " .. my.enemy_name:sub(1, 24)) else txt(10, "Enemy: -", C.dim); nl(17) end nl(6) header("-- War --") txt(10, string.format("God %s > %s next %ss", vmip.GOD_POWER or "?", vmip.GOD_POWER_FOCUS or "?", vmip.GOD_POWER_NEXT or "?")); nl() txt(10, string.format("Raid %s Blot %s", vmip.RAID or "?", (vmip.BLOT or "?"):sub(1, 16))); nl() nl(6) header("-- " .. (vmip.LIN or "?") .. " GLvl " .. (vmip.GLVL or "?") .. " --") local sub_lbl = string.format("Sub %s Daler ", vmip.SUB or "?") txt(10, sub_lbl) WindowText(WIN, "f", vmip.DALER or "?", 10 + WindowTextWidth(WIN, "f", sub_lbl), ly, 0, 0, C.good) nl() txt(10, string.format("Kap %s Aud %s Vis %s Soemd %s", vmip.KAP or "?", vmip.AUD or "?", vmip.VIS or "?", vmip.SOE or "?")); nl() txt(10, string.format("VKxp %s New %s Reg %s Tick %ss", vmip.VKXP or "?", vmip.VMNEW or "?", vmip.VMREG or "?", vmip.NEXTTICK or "?")); nl() local wx = split(vmip.WEATHER or "", "|") local dc = split(vmip.DCYCLE or "", "|") txt(10, string.format("Weather %s/%s Cycle %s", wx[1] or "?", wx[2] or "?", dc[1] or "?"), C.dim); nl() nl(6) local stfx = clean(vmip.STFX or ""):gsub("[%[%]]", "") if stfx ~= "" then -- TODO: per-spell colours once the full spell list is known. For now every -- effect uses the "undecided" yellow (C.warn). local x = 10 for tok in stfx:gmatch("%S+") do WindowText(WIN, "f", tok, x, ly, 0, 0, C.warn) x = x + (#tok + 1) * 7 if x > W - 60 then break end end nl() end nl(6) header("-- Combat --") txt(10, "Fury " .. clean(vmip.FURY or ""):sub(1, 12)); nl() txt(10, string.format("Threk %s / %s Chain %s Depth %s", vmip.THREK or "?", vmip.MTHREK or "?", vmip.CHAIN or "?", vmip.BSDEPTH or "?")); nl() txt(10, "Rounds " .. (vmip.RNDZ or "?")); nl() txt(10, "Last fight " .. (last_fight > 0 and tostring(last_fight) or "-")); nl() nl(6) header("-- Patrol --") if (vmip.PATROL or "") == "" then txt(10, "none on patrol", C.dim); nl() else local p = split(vmip.PATROL or "", "|") local mins = tonumber(p[2]) and (math.floor(num(p[2]) / 60) .. "m left") or "" txt(10, string.format("Hirdmadrs %s %s", p[1] or "?", mins)); nl() end -- click to commit a new patrol; number defaults to the last patrol's count local pn = patrol_number(vmip) local clbl = "Commit patrol: " .. (pn or "?") txt(10, clbl, C.good) local cw = WindowTextWidth(WIN, "f", clbl) WindowAddHotspot(WIN, "patrol_commit", 10, ly, 10 + cw, ly + 12, "", "", "vik_patrol_commit", "", "", "Send: vpatrol commit " .. (pn or "?"), 1, 0) local chx = 10 + cw + 14 txt(chx, "[change]", C.head) WindowAddHotspot(WIN, "patrol_setnum", chx, ly, chx + WindowTextWidth(WIN, "f", "[change]"), ly + 12, "", "", "vik_patrol_setnum", "", "", "Set a custom number to commit", 1, 0) nl() end
local function draw_settlers(my, vmip) header("-- Settlement --") txt(10, string.format("Blot %s Sproj %s Sact %s", (vmip.BLOT or "?"):sub(1, 14), vmip.SPROJ or "?", vmip.SACTIONS or "?")); nl() nl(4) header("-- Settlers --") local s = split(vmip.SETTLERS or "", "|") txt(10, string.format("Population %s Tax %s Mood %s", s[1] or "?", s[2] or "?", s[4] or "?")); nl() local mood = tonumber(s[4]) if mood then WindowRectOp(WIN, 2, 150, ly + 1, 400, ly + 12, C.panel) local fill = math.floor(248 * math.min(mood, 100) / 100) if fill > 0 then WindowRectOp(WIN, 2, 151, ly + 2, 151 + fill, ly + 11, grad(mood)) end WindowRectOp(WIN, 1, 150, ly + 1, 400, ly + 12, C.border) nl(16) end nl(4) header("-- Settler detail (raw) --") local sx = split(vmip.SETTLERX or "", "|") -- the feed has a leading empty field; real values follow it local vals = {} for i = 2, #sx do vals[#vals + 1] = sx[i] end if #vals == 0 then txt(10, "no data", C.dim); nl() else -- index:value (slots unlabelled until their meaning is known) local per = 9 local i = 1 while i <= #vals do local parts = {} for j = i, math.min(i + per - 1, #vals) do parts[#parts + 1] = string.format("%2d:%-4s", j, vals[j]) end txt(10, table.concat(parts, " "), C.text); nl() i = i + per end end nl(4) header("-- Civic --") local civ = {} for entry in (vmip.SCIVICS or ""):gmatch("[^;]+") do local name, lvl = entry:match("^(.-):(%d+)$") if name then name = name:gsub("_", " "):gsub("(%a)([%w]*)", function(a, b) return a:upper() .. b end) civ[#civ + 1] = name .. " T" .. lvl end end if #civ == 0 then txt(10, "none", C.dim); nl() else table.sort(civ) local rows = math.ceil(#civ / 2) for i = 1, rows do WindowText(WIN, "f", civ[i] or "", 10, ly, 0, 0, C.text) WindowText(WIN, "f", civ[i + rows] or "", 170, ly, 0, 0, C.text) nl(13) end end nl(4) header("-- Consumption (per cycle) --") local cons = {} for entry in (vmip.SCONSUME or ""):gmatch("[^;]+") do local res, amt = entry:match("^(.-):(%-?%d+)$") if res then cons[#cons + 1] = res .. " " .. amt end end txt(10, #cons > 0 and table.concat(cons, " ") or "none", #cons > 0 and C.text or C.dim); nl() end
local function draw_city(my, vmip) header("-- Ships --") local ships = split(vmip.SHIPS or "", ";") if #ships == 0 then txt(10, "none", C.dim); nl() else -- two columns so all 10 ships fit without clipping the panels below local slist = {} for i = 1, math.min(#ships, 10) do local f = split(ships[i], "|") local eta = tonumber(f[5]) and (math.floor(num(f[5]) / 60) .. "m") or "" slist[i] = { text = string.format("%-12s %-10s %s", f[1] or "?", f[4] or "", eta), col = C.text, } end local rows = math.ceil(#slist / 2) for i = 1, rows do local a, b = slist[i], slist[i + rows] WindowText(WIN, "f", a and a.text or "", 10, ly, 0, 0, a and a.col or C.text) if b then WindowText(WIN, "f", b.text, 286, ly, 0, 0, b.col) end nl(13) end end nl(4) header("-- Carts --") local carts = split(vmip.CARTS or "", ";") if #carts == 0 then txt(10, "no carts out", C.dim); nl() else for i = 1, math.min(#carts, 4) do local f = split(carts[i], "|") local eta = f[4] and (math.floor(num(f[4]) / 60) .. "m") or "?" txt(10, string.format("%-4s %-10s -> %-16s %5s x%s", f[1] or "?", f[2] or "?", f[3] or "?", eta, f[5] or "?")); nl() end end nl(4) -- warehouse with freshness bars local wb = (vmip.BUILDINGS or "") .. "," local tier = wb:match("warehouse:(%d+),") or "1" local wmax = ({ ["1"]=150, ["2"]=500, ["3"]=1000, ["4"]=2000, ["5"]=4000 })[tier] or 150 -- one row per good: total amount, avg-quality bar, stale batches noted local byg, tot = {}, 0 for _, e in ipairs(split(vmip.WSTOCK or "", ";")) do local f = split(e, "|") if f[1] then local amt, q = num(f[2]), tonumber(f[3]) or 100 local g = byg[f[1]] if not g then g = { amt = 0, qsum = 0, minq = 100, stale = 0 }; byg[f[1]] = g end g.amt = g.amt + amt g.qsum = g.qsum + q * amt if q < 100 then g.stale = g.stale + amt if q < g.minq then g.minq = q end end tot = tot + amt end end local stock = {} for good, g in pairs(byg) do stock[#stock + 1] = { good = good, g = g } end table.sort(stock, function(a, b) return a.good < b.good end) header(string.format("-- Warehouse %d / %d --", tot, wmax)) if #stock == 0 then txt(10, "empty", C.dim); nl() else for _, f in ipairs(stock) do local g = f.g local avgq = g.amt > 0 and math.floor(g.qsum / g.amt + 0.5) or 100 txt(10, string.format("%-10s %4d", f.good, g.amt)) WindowRectOp(WIN, 2, 150, ly + 1, 330, ly + 12, C.panel) local fill = math.floor(178 * math.min(avgq, 100) / 100) if fill > 0 then WindowRectOp(WIN, 2, 151, ly + 2, 151 + fill, ly + 11, grad(avgq)) end WindowRectOp(WIN, 1, 150, ly + 1, 330, ly + 12, C.border) if g.stale > 0 then txt(338, string.format("%d@%d%%", g.stale, g.minq), C.bad) else txt(338, "100%", C.dim) end nl(15) end end nl(4) local bh = "-- Buildings Daler " local dal = vmip.DALER or "?" txt(10, bh, C.head, "fb") local bx = 10 + WindowTextWidth(WIN, "fb", bh) WindowText(WIN, "fb", dal, bx, ly, 0, 0, C.good) txt(bx + WindowTextWidth(WIN, "fb", dal), " --", C.head, "fb") nl(15) -- tier -> colour (BGR): T1 white, T2 teal, T3 blue, T4 yellow, T5 red local TIERCOL = { ["1"] = 0xF0F0F0, ["2"] = 0xC0C000, ["3"] = 0xFF8040, ["4"] = 0x20E0F0, ["5"] = 0x4040FF } local blist = {} for entry in (vmip.BUILDINGS or ""):gmatch("[^,]+") do local name, tier = entry:match("^(.-):(%d+)$") if name then name = name:gsub("_", " "):gsub("(%a)([%w]*)", function(a, b) return a:upper() .. b end) blist[#blist + 1] = { text = name .. " T" .. tier, col = TIERCOL[tier] or C.text } end end table.sort(blist, function(a, b) return a.text < b.text end) if #blist == 0 then txt(10, "none", C.dim); nl() else -- two columns, like the in-game display local rows = math.ceil(#blist / 2) for i = 1, rows do local a, b = blist[i], blist[i + rows] WindowText(WIN, "f", a and a.text or "", 10, ly, 0, 0, a and a.col or C.text) if b then WindowText(WIN, "f", b.text, 286, ly, 0, 0, b.col) end nl(13) end end local builds = split(vmip.BUILDS or "", ";") if #builds > 0 then for i = 1, math.min(#builds, 3) do local f = split(builds[i], "|") local mins = f[5] and (math.floor(num(f[5]) / 60) .. "m left") or "?" txt(10, string.format("constr: %-14s %s %s", f[1] or "?", mins, f[7] or ""), C.warn); nl() end end end
local function draw_people(my, vmip) header("-- Forces --") txt(10, string.format("Thralls %s Followers %s", vmip.THRALLS or "?", (vmip.THRALL_FOLLOWER or "?"):sub(1, 30))); nl() txt(10, string.format("Garrison %s Threk %s", vmip.GARRISON or "?", vmip.MTHREK or "?")); nl() nl(4) header("-- Hird Guard --") local hird = split(vmip.HIRD or "", ";") if #hird == 0 then txt(10, "no hird", C.dim); nl() else for i = 1, math.min(#hird, 10) do local f = split(hird[i], "|") txt(10, string.format("%-16s %s/%s/%s/%s %s %s", f[2] or "?", f[4] or "?", f[5] or "?", f[6] or "?", f[7] or "?", f[9] or "?", f[10] or "?")); nl() end end nl(4) header("-- Staff --") local staff = split(vmip.STAFF or "", ";") if #staff == 0 then txt(10, "no staff hired", C.dim); nl() else txt(10, string.format("%-16s %-13s %-4s%-4s%-4s%-4s%-4s%-4s%-4s", "", "", "Cbt", "Trd", "Cft", "Sea", "Wld", "Lnd", "Chm"), C.dim); nl(13) for i = 1, math.min(#staff, 10) do local f = split(staff[i], "|") local s = split(f[4] or "", ",") txt(10, string.format("%-16s %-13s %-4s%-4s%-4s%-4s%-4s%-4s%-4s", f[1] or "?", f[2] or "?", s[1] or "?", s[2] or "?", s[3] or "?", s[4] or "?", s[5] or "?", s[6] or "?", s[7] or "?")); nl(13) end end nl(4) header("-- Bonds --") local bonds = split(vmip.BONDS or "", ";") if #bonds == 0 then txt(10, "no bonds", C.dim); nl() else -- member number -> short (first) name from HIRD; the truncated feed may not -- name members 4+, which then show as #n local name = {} for _, h in ipairs(split(vmip.HIRD or "", ";")) do local f = split(h, "|") if f[1] and f[2] then name[f[1]] = (f[2]:match("^(%S+)") or f[2]) end end -- matrix[a][b] = 4th field of the bond; collect the member ids present local m, ids, seen = {}, {}, {} for _, b in ipairs(bonds) do local f = split(b, "|") local a, c, val = f[1], f[2], f[4] or "?" if a and c then m[a] = m[a] or {}; m[a][c] = val m[c] = m[c] or {}; m[c][a] = val if not seen[a] then seen[a] = true; ids[#ids + 1] = a end if not seen[c] then seen[c] = true; ids[#ids + 1] = c end end end table.sort(ids, function(x, y) return (tonumber(x) or 0) < (tonumber(y) or 0) end) local hdr = string.rep(" ", 11) for _, c in ipairs(ids) do hdr = hdr .. string.format("%-4s", c) end txt(10, hdr, C.dim); nl() for _, a in ipairs(ids) do local row = string.format("%-2s%-9s", a, (name[a] or ("#" .. a)):sub(1, 8)) for _, c in ipairs(ids) do if a == c then row = row .. string.format("%-4s", "-") else row = row .. string.format("%-4s", (m[a] and m[a][c]) or ".") end end txt(10, row, C.text); nl() end end end
local last_tgoods = nil -- cache: a momentarily-empty feed update shouldn't blank/jump the tab local function draw_goods(my, vmip) local vrep = parse_idx_table(vmip.VREP) if (vmip.TGOODS or "") ~= "" then last_tgoods = vmip.TGOODS end local entries = split(last_tgoods or "", "|") if #entries == 0 then header("-- Goods --") txt(10, "(no trade feed - vtoggle mip_trade_goods)", C.dim); nl() return end -- collect per-good lists: { town, lvl, sup, dem } local per = {} for _, e in ipairs(entries) do local idx, goods = e:match("^(%d+)=(.*)$") if idx then local name = HOLDCITY[tonumber(idx)] or (vrep[tonumber(idx)] or {})[2] or ("Hold " .. idx) for _, gd in ipairs(split(goods, ";")) do local l, lvl, sup, dem = gd:match("^(%a):(%-?%d+):(%d+):(%d+)$") if l then per[l] = per[l] or {} per[l][#per[l] + 1] = { town = name, lvl = tonumber(lvl), sup = tonumber(sup), dem = tonumber(dem) } end end end end local order = { "t", "i", "g", "f", "h", "m", "a", "r", "s" }
-- one section: the 2 best cities per good, sorted by `key` (desc) local function section(title, key, vcol) header(title) -- always render every good (fixed row count) so the section can't resize -- when a good momentarily drops out of the feed for _, l in ipairs(order) do local list = per[l] or {} local s = {} for i, r in ipairs(list) do s[i] = r end table.sort(s, function(a, b) return a[key] > b[key] end) txt(10, (GOODS_NAME[l] or l):sub(1, 9), C.label) local xs = { 86, 310 } for i = 1, 2 do local r = s[i] if r and r[key] > 0 then txt(xs[i], r.town:sub(1, 15), C.text) txt(xs[i] + 132, string.format("%4d", r[key]), vcol) if r.lvl and r.lvl ~= 0 then txt(xs[i] + 170, string.rep(r.lvl > 0 and "+" or "-", math.min(math.abs(r.lvl), 3)), r.lvl > 0 and C.good or C.bad) end else txt(xs[i], "-", C.dim) end end nl(14) end end
section("-- Best place to BUY (top supply) --", "sup", C.good) nl(6) section("-- Best place to SELL (top demand) --", "dem", C.warn) nl(6) txt(10, "+/- = demand-cycle trend for that good in that city", C.dim); nl() end
local function draw_holds(my, vmip) header("-- Holds: standing & reputation --") local vrep = parse_idx_table(vmip.VREP) local stand = parse_idx_table(vmip.STANDINGS) WindowText(WIN, "f", string.format("%-16s %-10s %6s %6s", "Hold", "Standing", "Bond", "Rep"), 10, ly, 0, 0, C.dim); nl() for i = 0, 20 do local v, s = vrep[i], stand[i] if v or s then local name = HOLDCITY[i] or (v and v[2]) or (s and s[2]) or ("?" .. i) local standing = (s and s[4]) or "-" -- standing -> colour (add tiers here as they're unlocked) local scol = (standing == "Allied" and 0x40FF40) -- brighter green (above Friendly) or (standing == "Friendly" and C.good) -- green or (standing == "Hostile" and C.bad) -- red or C.label -- default (Neutral, etc.) WindowText(WIN, "f", string.format("%-16s", name:sub(1, 16)), 10, ly, 0, 0, C.text) WindowText(WIN, "f", string.format("%-10s", standing), 129, ly, 0, 0, scol) WindowText(WIN, "f", string.format("%6s %6s", (s and s[3]) or "-", (v and v[3]) or "-"), 204, ly, 0, 0, C.label) nl(13) end end nl(8) header("-- War status --") local blot = split(vmip.BLOT or "", "|") txt(10, string.format("Blot %s pool %s (%s/%s)", blot[1] or "?", blot[2] or "?", blot[3] or "?", blot[4] or "?")); nl() local raid = split(vmip.RAID or "", "|") txt(10, string.format("Raid %s %s %s Garrison %s", raid[1] or "?", raid[2] or "", raid[3] or "", vmip.GARRISON or "?")); nl() txt(10, string.format("Monuments %s Varangians %s", vmip.MONUMENTS or "?", (vmip.VARANG == "^" or vmip.VARANG == "") and "none" or (vmip.VARANG or "?"))); nl() end
-- voyage chart char -> colour (BGR) local SEACHART = { ["#"] = 0x303030, -- unrevealed ["O"] = 0xD0A000, ["~"] = 0xD0A000, -- open sea ["F"] = 0x909090, -- fog ["?"] = 0x505050, -- unknown ["I"] = 0x20C0C0, -- island ["H"] = 0x40C040, -- harbor ["W"] = 0x4040E0, -- wreck ["T"] = 0x5050F0, -- storm ["X"] = 0xE060E0, -- objective ["S"] = 0xFFFFFF, -- your ship ["+"] = 0x60E060, [">"] = 0x60E0E0, -- queued path / destination ["="] = 0xD06000, -- crosscurrent } local SEALETTER = { S = true, X = true, H = true, W = true, T = true, I = true, [">"] = true }
local function draw_sea(my, vmip) local v = split(vmip.VOYAGE or "", "|") if #v < 10 then header("-- Sea --") txt(10, "No voyage under way.", C.dim); nl() local ships = split(vmip.SHIPS or "", ";") if #ships > 0 and ships[1] ~= "" then nl(4) header("-- Fleet --") if (vmip.SHPLOTS or "") ~= "" then txt(10, "Ship plots: " .. (vmip.SHPLOTS or ""):gsub("|", " / "), C.dim); nl() end -- SHIPS holds the whole fleet (name | ? | status | dest | ...) for i = 1, math.min(#ships, 10) do local f = split(ships[i], "|") txt(10, string.format("%-13s %-9s %s", f[1] or "?", f[3] or "?", f[4] or "")); nl() end end return end header(string.format("-- Voyage: %s - %s (%s) --", v[3] or "?", v[4] or "?", v[5] or "?")) -- left column: text facts / right column: condition bars local top = ly txt(10, string.format("State: %s", v[1] or "?")); nl() txt(10, string.format("Position: %s,%s", v[6] or "?", v[7] or "?")); nl() txt(10, string.format("Threat: %s [%s]", v[19] or "-", v[20] or "?")); nl() txt(10, string.format("Pressure: %s Danger: %s", v[21] or "?", v[8] or "?")); nl() txt(10, string.format("Captain: %s", v[25] or "?")); nl() txt(10, string.format("Identity: %s", v[26] or "?")); nl() txt(10, ("Traits: " .. (v[27] or "") .. ", " .. (v[28] or "")):sub(1, 40), C.dim); nl() local bottom = ly ly = top local function seabar(label, val, invert) local n = num(val) local pct = invert and (100 - n) or n WindowText(WIN, "f", label, 300, ly, 0, 0, C.label) WindowRectOp(WIN, 2, 366, ly + 1, 496, ly + 12, C.panel) local fill = math.floor(128 * math.min(math.max(pct, 0), 100) / 100) if fill > 0 then WindowRectOp(WIN, 2, 367, ly + 2, 367 + fill, ly + 11, grad(pct)) end WindowRectOp(WIN, 1, 366, ly + 1, 496, ly + 12, C.border) WindowText(WIN, "f", n .. "%", 502, ly + 1, 0, 0, C.text) nl() end seabar("Hull", v[11]) seabar("Morale", v[12]) seabar("Supplies", v[13]) seabar("Stress", v[14], true) WindowText(WIN, "f", string.format("Crew %s/%s", v[15] or "?", v[16] or "?"), 300, ly, 0, 0, C.text); nl() local wx = split(vmip.WEATHER or "", "|") WindowText(WIN, "f", string.format("Weather: %s/%s", wx[1] or "?", wx[2] or "?"), 300, ly, 0, 0, C.dim); nl() ly = math.max(ly, bottom) + 4 -- chart local ch = split(vmip.VCHH or "", "|") local cw, chh = num(ch[1]), num(ch[2]) if cw > 0 then header(string.format("-- Chart %dx%d (%s) --", cw, chh, ch[3] or "?")) local bs = math.max(8, math.min(16, math.floor(380 / math.max(cw, 1)))) local x0, y0 = 14, ly + 2 local unknown = {} for row = 0, chh - 1 do local rowstr = vmip[string.format("VCR%02d", row)] if rowstr then for col = 1, math.min(#rowstr, cw) do local c = rowstr:sub(col, col) local colr = SEACHART[c] if not colr then colr = 0x404040; unknown[c] = true end WindowRectOp(WIN, 2, x0 + (col - 1) * bs, y0 + row * bs, x0 + col * bs - 1, y0 + (row + 1) * bs - 1, colr) if SEALETTER[c] then WindowText(WIN, "fb", c, x0 + (col - 1) * bs + math.floor(bs / 2) - 4, y0 + row * bs + math.floor(bs / 2) - 7, 0, 0, c == "S" and 0x000000 or 0xFFFFFF) end end end end WindowRectOp(WIN, 1, x0 - 1, y0 - 1, x0 + cw * bs + 1, y0 + chh * bs + 1, C.border) -- legend beside the chart local lx = x0 + cw * bs + 14 local lyy = y0 for _, lg in ipairs({ {"S ship",0xFFFFFF}, {"X objective",0xE060E0}, {"H harbor",0x40C040}, {"W wreck",0x4040E0}, {"T storm",0x5050F0}, {"I island",0x20C0C0}, {"F fog",0x909090}, {"# unrevealed",0x303030}, {"O open sea",0xD0A000} }) do WindowRectOp(WIN, 2, lx, lyy + 2, lx + 8, lyy + 10, lg[2]) WindowText(WIN, "f", lg[1], lx + 12, lyy, 0, 0, C.dim) lyy = lyy + 14 end ly = y0 + chh * bs + 6 local u = {} for c in pairs(unknown) do u[#u + 1] = c end if #u > 0 then table.sort(u) txt(10, "unmapped chart chars: " .. table.concat(u, " ") .. " (tell Claude)", C.dim); nl(13) end end -- saga local saga = split(vmip.VSAGA or "", ";") if #saga > 0 then header("-- Saga --") for i = math.max(1, #saga - 2), #saga do if ly > H - 16 then break end txt(10, saga[i]:sub(1, 74), C.dim); nl(13) end end end
local function draw_map(my, vmip) local hd = split(vmip.VMAPH or "", "|") local mw, mh, px, py = num(hd[1]), num(hd[2]), num(hd[3]), num(hd[4]) if mw == 0 then txt(10, "(no map feed - run vmapon)", C.dim); nl() return end header(string.format("-- Territory %dx%d @ %d,%d --", mw, mh, px, py)) -- legend local legend = { {"Tund",0x606060},{"Hill",0x20C0C0},{"Mtn",0x3030D0},{"Frst",0x208020}, {"Plns",0x60C060},{"Watr",0xD0A000},{"Road",0x181818},{"Gate",0x909090}, {"Lin",0x2080E0},{"Set",0x40C0E0},{"You",0xFFFFFF} } local lx = 10 for _, lg in ipairs(legend) do WindowRectOp(WIN, 2, lx, ly + 2, lx + 8, ly + 10, lg[2]) WindowText(WIN, "f", lg[1], lx + 10, ly, 0, 0, C.dim) lx = lx + 10 + #lg[1] * 7 + 7 end nl(16) local bs = math.max(4, math.min(10, math.floor(520 / math.max(mw, 1)))) local x0, y0 = 14, ly + 2 local unknown = {} local POI_LABEL = { L = "Lin", S = "Set", C = "Cap", ["*"] = "POI", R = "Ruin", M = "Cap" } local pois = {} for row = 0, mh - 1 do local rowstr = vmip[string.format("VMR%02d", row)] local mask = vmip[string.format("MEE%02d", row)] if rowstr then for col = 1, math.min(#rowstr, mw) do local ch = rowstr:sub(col, col) local colr = TERRAIN[ch] if not colr then colr = 0x282828; unknown[ch] = true end if mask and mask:sub(col, col) == "0" then colr = 0x000000 end WindowRectOp(WIN, 2, x0 + (col - 1) * bs, y0 + row * bs, x0 + col * bs, y0 + (row + 1) * bs, colr) if POI_LABEL[ch] then pois[#pois + 1] = { x = col - 1, y = row, ch = ch } end end end end -- hover a town for its type, name and coordinates local locs = parse_locs(vmip.VMAPL) local feednames = {} for _, lc in ipairs(locs) do feednames[lc.x .. "|" .. lc.y] = lc.name end for _, p in ipairs(pois) do local key = p.x .. "|" .. p.y local label = (POI_LABEL[p.ch] or "?") .. " (" .. p.x .. "," .. p.y .. ")" local nm = locname(p.x, p.y) or feednames[key] if nm then label = nm .. " - " .. label end WindowAddHotspot(WIN, "poi_" .. key, x0 + p.x * bs, y0 + p.y * bs, x0 + (p.x + 1) * bs, y0 + (p.y + 1) * bs, "", "", "", "", "", label, 0, 0) end -- location markers for _, lc in ipairs(locs) do if lc.x >= 0 and lc.x < mw and lc.y >= 0 and lc.y < mh then WindowRectOp(WIN, 1, x0 + lc.x * bs - 1, y0 + lc.y * bs - 1, x0 + (lc.x + 1) * bs + 1, y0 + (lc.y + 1) * bs + 1, loc_color(lc.type)) end end -- player marker WindowRectOp(WIN, 2, x0 + px * bs - 1, y0 + py * bs - 1, x0 + (px + 1) * bs + 1, y0 + (py + 1) * bs + 1, 0xFFFFFF) WindowRectOp(WIN, 1, x0 - 1, y0 - 1, x0 + mw * bs + 1, y0 + mh * bs + 1, C.border) ly = y0 + mh * bs + 6 -- merged list: feed-named locations + towns scanned from the grid local merged, seen = {}, {} for _, lc in ipairs(locs) do seen[lc.x .. "|" .. lc.y] = true lc.name = locname(lc.x, lc.y) or lc.name merged[#merged + 1] = lc end for _, p in ipairs(pois) do local key = p.x .. "|" .. p.y if not seen[key] then seen[key] = true merged[#merged + 1] = { type = POI_LABEL[p.ch], name = locname(p.x, p.y), x = p.x, y = p.y } end end -- known locations always listed, even with no marker on the map local known = {} for key in pairs(TRAVEL_CODE) do known[key] = true end for key in pairs(DEFAULT_LOCNAMES) do known[key] = true end for key in pairs(known) do if not seen[key] then local x, y = key:match("^(%-?%d+)|(%-?%d+)$") local typ if TRAVEL_CODE[key] then typ = (key == "32|16") and "Cap" or "Lin" else typ = DEFAULT_LOCTYPE[key] or "POI" end merged[#merged + 1] = { type = typ, name = locname(tonumber(x), tonumber(y)), x = tonumber(x), y = tonumber(y) } end end if #merged > 0 then local function rank(e) if TRAVEL_CODE[e.x .. "|" .. e.y] then return 1 end if e.name then return 2 end return 3 end table.sort(merged, function(a, b) local ra, rb = rank(a), rank(b) if ra ~= rb then return ra < rb end if a.name and b.name then return a.name < b.name end if a.y ~= b.y then return a.y < b.y end return a.x < b.x end) header("-- Locations (click a town to walk there) --") local colx, coltop = 10, ly local maxly = ly for _, lc in ipairs(merged) do if ly > H - 29 then if colx == 10 then maxly = math.max(maxly, ly) colx = 286; ly = coltop else break end end local t = (lc.type or "?"):gsub("_.*$", "") t = t:sub(1, 1):upper() .. t:sub(2) local key2 = lc.x .. "|" .. lc.y local clickable = TRAVEL_CODE[key2] ~= nil WindowText(WIN, "f", t, colx, ly, 0, 0, loc_color(lc.type)) WindowText(WIN, "f", string.format("%-14s (%d,%d)", (lc.name or "-"):sub(1, 14), lc.x, lc.y), colx + 50, ly, 0, 0, clickable and 0x40E0E0 or (lc.name and C.label or C.dim)) if clickable then WindowAddHotspot(WIN, "trav_" .. key2, colx, ly, colx + 264, ly + 12, "", "", "vik_travel_click", "", "", "Click: walk to " .. (lc.name or "here") .. " Right-click: I am here", 1, 0) end nl(13) end ly = math.max(maxly, ly) end local u = {} for ch in pairs(unknown) do u[#u + 1] = ch end if #u > 0 then table.sort(u) txt(10, "unmapped terrain chars: " .. table.concat(u, " ") .. " (tell Claude)", C.dim); nl(13) end end
local function draw_feeds(my, vmip) header("-- Live feed keys (for building more tabs) --") local keys = {} for k in pairs(vmip) do if not k:match("^VMR%d") and not k:match("^MEE%d") and not k:match("^MES%d") and not k:match("^VCR%d") then keys[#keys + 1] = k end end table.sort(keys) local top, x = ly, 10 for _, k in ipairs(keys) do if ly > H - 16 then if x == 10 then x = 286; ly = top else txt(x, "...", C.dim) break end end local v = vmip[k] txt(x, string.format("%-13s %s", k:sub(1, 13), v:sub(1, 24)), #v > 0 and C.text or C.dim); nl(13) end end
-- wrapper so each mission/errand town gets a unique hotspot id while still -- delegating to the map's travel handler (id carries the x|y before the @uid). function vik_mtravel(flags, id) local coords = id:match("^mtrav_([%-%d|]+)@") if coords then vik_travel_click(flags, "trav_" .. coords) end end
-- click a mission number to send "vmission fulfill <number>" function vik_fulfill(flags, id) local num = id:match("^mfulfill_(%d+)$") if num then Send("vmission fulfill " .. num) end end
-- newbie errand buttons function vik_mnewbie(flags, id) if id == "mfetch" then Send("vmission newbie fetch") elseif id == "msubmit" then Send("vmission newbie submit") end end
-- patrol: commit a new patrol (number defaults to the last patrol's count) function vik_patrol_commit(flags, id) local _, vmip = getvars() local n = patrol_number(vmip) if n then Send("vpatrol commit " .. n) else Note("[viking] no patrol number known - use [change] to set one") end end
function vik_patrol_setnum(flags, id) local s = utils.inputbox("Hirdmadrs to commit (blank = use last patrol's count):", "Patrol commit number", GetVariable("patrol_num") or "") if not s then return end s = s:gsub("%D", "") SetVariable("patrol_num", s) -- "" clears the override -> back to default Note("[viking] patrol commit number: " .. (s ~= "" and s or "default (last patrol count)")) vik_draw() end
-- map a settlement name to its travel key (x|y), if it is travel-reachable -- normalise a town name for matching: lowercase, drop apostrophes/spaces/punctuation local function normtown(s) return ((s or ""):lower():gsub("[^%w]", "")) end local function town_travel_key(name) local target = normtown(name) for k, n in pairs(locnames) do if TRAVEL_CODE[k] and normtown(n) == target then return k end end for k, n in pairs(DEFAULT_LOCNAMES) do if TRAVEL_CODE[k] and normtown(n) == target then return k end end return nil end
-- draw a town name at (x, ly); if reachable, colour it cyan and overlay a -- click-to-travel hotspot (same routing as the Map tab) local function draw_town(x, name, uid) local key = town_travel_key(name) WindowText(WIN, "f", name, x, ly, 0, 0, key and C.head or C.text) if key then local w = WindowTextWidth(WIN, "f", name) WindowAddHotspot(WIN, "mtrav_" .. key .. "@" .. uid, x, ly, x + w, ly + 12, "", "", "vik_mtravel", "", "", "click to travel to " .. name, 1, 0) end end
local function draw_mission(my, vmip) header("-- Missions --") if (vmip.MISSIONS or "") == "" then txt(10, "no missions", C.dim); nl() else txt(10, "no", C.dim); txt(56, "town", C.dim); txt(160, "needs", C.dim); txt(330, "rep", C.dim); nl() for i, ms in ipairs(split(vmip.MISSIONS, ";")) do local f = split(ms, "|") -- id | desc | rep | ? | expiry | (empty) | town | goods(good:qty,...) local goods = (f[8] or ""):gsub(":", ""):gsub(",", " "):sub(1, 22) local mnum = f[1] or "?" WindowText(WIN, "f", mnum, 10, ly, 0, 0, C.good) WindowAddHotspot(WIN, "mfulfill_" .. mnum, 10, ly, 10 + WindowTextWidth(WIN, "f", mnum), ly + 12, "", "", "vik_fulfill", "", "", "click to fulfill mission " .. mnum, 1, 0) draw_town(56, f[7] or "?", "m" .. i) txt(160, goods) txt(330, f[3] or "?") nl() end end nl(6) header("-- Errand --") if (vmip.ERRAND or "") == "" then txt(10, "no errand", C.dim); nl() else local e = split(vmip.ERRAND, "|") -- id | desc | rep | timelimit(s) | from | to | good | qty txt(10, (e[2] or "?"):sub(1, 58)); nl() local fromn, ton = e[5] or "?", e[6] or "?" draw_town(10, fromn, "ef") local x2 = 10 + WindowTextWidth(WIN, "f", fromn) txt(x2, " -> ") local x3 = x2 + WindowTextWidth(WIN, "f", " -> ") draw_town(x3, ton, "et") local x4 = x3 + WindowTextWidth(WIN, "f", ton) local mins = tonumber(e[4]) and (math.floor(num(e[4]) / 60) .. "m") or "?" txt(x4, string.format(" %s x%s %s rep %s", e[7] or "?", e[8] or "?", e[3] or "?", mins)) nl() end -- newbie errand action buttons nl(4) local function mbtn(id, x1, label, tip) WindowRectOp(WIN, 2, x1, ly, x1 + 70, ly + 15, C.panel) WindowRectOp(WIN, 1, x1, ly, x1 + 70, ly + 15, C.border) WindowText(WIN, "fb", label, x1 + 35 - #label * 4, ly + 2, 0, 0, C.head) WindowAddHotspot(WIN, id, x1, ly, x1 + 70, ly + 15, "", "", "vik_mnewbie", "", "", tip, 1, 0) end mbtn("mfetch", 10, "Fetch", "Send: vmission newbie fetch") mbtn("msubmit", 90, "Submit", "Send: vmission newbie submit") nl(18) end
-- ---------------- main draw ---------------- function vik_draw() local my, vmip = getvars() -- track combat rounds: when RNDZ drops (combat ended / new fight reset its -- counter), the value just before the drop was the last fight's round count. local cur = tonumber(vmip.RNDZ) if cur then if prev_rndz and cur < prev_rndz then last_fight = prev_rndz SetVariable("last_fight", tostring(last_fight)) end prev_rndz = cur end if not visible then return end if not windowinfo then windowinfo = movewindow.install(WIN, 6, 0) end WindowCreate(WIN, windowinfo.window_left, windowinfo.window_top, W, H, windowinfo.window_mode, windowinfo.window_flags, C.bg) WindowFont(WIN, "f", "Lucida Console", 9, false, false, false, false) WindowFont(WIN, "fb", "Lucida Console", 9, true, false, false, false) WindowRectOp(WIN, 1, 0, 0, W, H, C.border) -- title bar (drag) WindowRectOp(WIN, 2, 1, 1, W - 1, 18, C.title) WindowText(WIN, "fb", "Viking Status", math.floor(W / 2) - 45, 3, 0, 0, C.head) movewindow.add_drag_handler(WIN, 0, 0, W, 18, miniwin.cursor_hand) -- tabs local per = math.ceil(#TABS / 2) -- tabs across; two rows local tw = math.floor((W - 2) / per) for i, t in ipairs(TABS) do local r = math.floor((i - 1) / per) -- row 0 (top) or 1 (bottom) local c = (i - 1) % per local x1 = 1 + c * tw local y1 = 19 + r * 19 local y2 = y1 + 18 local sel = (t == tab) WindowRectOp(WIN, 2, x1, y1, x1 + tw - 1, y2, sel and C.tabsel or C.tabbg) WindowRectOp(WIN, 1, x1, y1, x1 + tw - 1, y2, C.border) WindowText(WIN, sel and "fb" or "f", t, x1 + math.floor(tw / 2) - #t * 4, y1 + 4, 0, 0, sel and C.head or C.label) WindowAddHotspot(WIN, "tab_" .. t, x1, y1, x1 + tw - 1, y2, "", "", "vik_tabclick", "", "", t, 1, 0) end ly = 63 if tab == "Stats" then draw_stats(my, vmip) elseif tab == "City" then draw_city(my, vmip) elseif tab == "People" then draw_people(my, vmip) elseif tab == "Settlers" then draw_settlers(my, vmip) elseif tab == "Goods" then draw_goods(my, vmip) elseif tab == "Holds" then draw_holds(my, vmip) elseif tab == "Sea" then draw_sea(my, vmip) elseif tab == "Map" then draw_map(my, vmip) elseif tab == "Mission" then draw_mission(my, vmip) elseif tab == "Feeds" then draw_feeds(my, vmip) end WindowShow(WIN, true) end
function vik_tabclick(flags, id) tab = id:sub(5) SetVariable("tab", tab) vik_draw() end
function vik_settab(name) name = name:sub(1, 1):upper() .. name:sub(2):lower() for _, t in ipairs(TABS) do if t == name then tab = t; SetVariable("tab", tab); vik_draw(); return end end Note("[viking] no tab '" .. name .. "' (Stats City People Map Feeds)") end
function vik_dump() local dir = GetPluginInfo(GetPluginID(), 20) local path = dir .. "vmip_dump.txt" local f = io.open(path, "w") if not f then Note("[viking] could not write " .. path) return end local my, vmip = getvars() local keys = {} for k in pairs(vmip) do keys[#keys + 1] = k end table.sort(keys) f:write("vmip dump " .. os.date() .. "\n") for _, k in ipairs(keys) do f:write(k .. " = " .. vmip[k] .. "\n") end f:close() Note("[viking] full feed written to " .. path) end
function vik_toggle() visible = not visible SetVariable("visible", visible and "1" or "0") if visible then vik_draw() else WindowShow(WIN, false) end Note("[viking] window " .. (visible and "shown" or "hidden")) end
function OnPluginBroadcast(msg, id, name, text) -- Goods tab is frozen for now (it jumped/resized on feed updates - WIP). -- Skip the feed-driven redraw while it's the active tab; it still refreshes -- when you click onto it. TODO: fix the Goods redraw, then remove this guard. if id == MIP_ID and tab ~= "Goods" then vik_draw() end end
function vik_tick(state) if state == "on" then AddTimer("viking_keepalive", 0, 5, 0, "l", timer_flag.Enabled + timer_flag.Replace, "") SetVariable("tick", "1") else EnableTimer("viking_keepalive", false) SetVariable("tick", "0") end Note("[viking] keepalive 'l' every 5 min: " .. state) end
function OnPluginSaveState() if windowinfo then movewindow.save_state(WIN) end SetVariable("visible", visible and "1" or "0") SetVariable("tab", tab) end
function OnPluginInstall() AddTimer("viking_keepalive", 0, 5, 0, "l", timer_flag.Replace, "") if GetVariable("tick") == "1" then EnableTimer("viking_keepalive", true) end vik_draw() end
function OnPluginEnable() vik_draw() end function OnPluginDisable() WindowShow(WIN, false) end
